mapper.select:
SELECT ITEM_ID, TICKER, ITEM_NM, MARKET
FROM STOCK_ITEM
WHERE TICKER = #{ticker}

WITH MAX_DATE AS ( SELECT MAX(TRADE_DATE) AS DT FROM STOCK_PRICE ) SELECT P.OPEN_PRICE AS mkp, P.CLOSE_PRICE AS clpr, P.HIGH_PRICE AS hipr, P.LOW_PRICE AS lopr, P.VOLUME AS trqu, DATE_FORMAT(P.TRADE_DATE, '%Y%m%d') AS basDt, I.ITEM_ID AS itemId, I.TICKER AS srtnCd, I.ITEM_NM AS itmsNm, I.MARKET AS mrktCtg FROM STOCK_PRICE P JOIN STOCK_ITEM I ON P.ITEM_ID = I.ITEM_ID JOIN MAX_DATE M ON P.TRADE_DATE = M.DT WHERE I.ITEM_ID IN
#{id}
ORDER BY P.VOLUME DESC
